87	// Strategy: Build L-shaped walls in two opposite corners, sealing off pet-free zones.
88	// Each corner has 2 free boundary walls, so only need 2 wall segments.
89	// This is much cheaper than full horizontal walls and adapts to pet positions.
90	
91	struct CornerPlan {
92	    int corner; // 0=TL, 1=TR, 2=BL, 3=BR
93	    int wall_row; // the horizontal wall row
94	    int wall_col; // the vertical wall column
95	    int area;
96	    int cost; // number of wall cells needed
97	    int pets_inside;
98	    double score;
99	    // The sealed region boundaries
100	    int r_min, r_max, c_min, c_max;
101	};
102	
103	// Wall cells for a corner plan
104	std::vector<Point> get_wall_cells(const CornerPlan& plan) {
105	    std::vector<Point> cells;
106	    if (plan.corner == 0) { // Top-Left: wall at row wall_row (cols 1..wall_col), col wall_col (rows 1..wall_row-1)
107	        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
108	        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
109	    } else if (plan.corner == 1) { // Top-Right: wall at row wall_row (cols wall_col..30), col wall_col (rows 1..wall_row-1)
110	        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
111	        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
112	    } else if (plan.corner == 2) { // Bottom-Left: wall at row wall_row (cols 1..wall_col), col wall_col (rows wall_row+1..30)
113	        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
114	        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
115	    } else { // Bottom-Right: wall at row wall_row (cols wall_col..30), col wall_col (rows wall_row+1..30)
116	        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
117	        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
118	    }
119	    return cells;
120	}
121	
122	bool is_safe_side(const CornerPlan& plan, int r, int c) {
123	    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
124	}
125	
126	// Find the best pair of corners (opposite corners)
127	CornerPlan plans[2];
128	int num_plans;
129	
130	void find_best_corner(int corner_id, CornerPlan& best) {
131	    best.score = -1;
132	
133	    for (int wr = 2; wr <= 29; wr++) {
134	        for (int wc = 2; wc <= 29; wc++) {
135	            int pets_inside = 0;
136	            int area = 0;
137	            int cost = 0;
138	            int r_min, r_max, c_min, c_max;
139	
140	            if (corner_id == 0) { // Top-Left: sealed region [1..wr-1] x [1..wc-1]
141	                r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
142	                cost = wc + (wr - 1); // horizontal wall has wc cells, vertical has wr-1 cells
143	            } else if (corner_id == 1) { // Top-Right: sealed region [1..wr-1] x [wc+1..30]
144	                r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
145	                cost = (GRID_SIZE - wc + 1) + (wr - 1);
146	            } else if (corner_id == 2) { // Bottom-Left: sealed region [wr+1..30] x [1..wc-1]
147	                r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
148	                cost = wc + (GRID_SIZE - wr);
149	            } else { // Bottom-Right: sealed region [wr+1..30] x [wc+1..30]
150	                r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
151	                cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
152	            }
153	
154	            area = (r_max - r_min + 1) * (c_max - c_min + 1);
155	            if (area < 50) continue; // too small
156	            if (cost > 40) continue; // too expensive
157	
158	            for (auto& p : pets) {
159	                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
160	                    pets_inside++;
161	                }
162	            }
163	
164	            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
165	
166	            // Penalize by construction cost (more cells = more time = more leakage)
167	            double time_factor = 1.0 / (1.0 + cost * 0.01);
168	
169	            // Heavily reward 0 pets inside
170	            double pet_bonus = (pets_inside == 0) ? 2.0 : 1.0;
171	
172	            double score = base_score * time_factor * pet_bonus;
173	
174	            if (score > best.score) {
175	                best.corner = corner_id;
176	                best.wall_row = wr;
177	                best.wall_col = wc;
178	                best.area = area;
179	                best.cost = cost;
180	                best.pets_inside = pets_inside;
181	                best.score = score;
182	                best.r_min = r_min;
183	                best.r_max = r_max;
184	                best.c_min = c_min;
185	                best.c_max = c_max;
186	            }
187	        }
188	    }
189	}
190	
191	// Also compute dual horizontal wall score for comparison
192	double compute_dual_wall_score(int tr, int br) {
193	    int pets_above = 0, pets_below = 0;
194	    for (auto& p : pets) {
195	        if (p.r < tr) pets_above++;
196	        else if (p.r > br) pets_below++;
197	    }
198	    int area_above = (tr - 1) * GRID_SIZE;
199	    int area_below = (GRID_SIZE - br) * GRID_SIZE;
200	    double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
201	    double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
202	    return (sa + sb) / 2.0;
203	}
204	
205	// Mode: 0 = dual L-shape, 1 = dual horizontal walls (fallback)
206	int strategy_mode;
207	int dual_wall_top, dual_wall_bot;
208	
209	void choose_strategy() {
210	    // Find best corner plans for each corner
211	    CornerPlan corners[4];
212	    for (int i = 0; i < 4; i++) {
213	        find_best_corner(i, corners[i]);
214	    }
215	
216	    // Best pair of opposite corners
217	    double best_pair_score = -1;
218	    int best_pair[2] = {0, 3};
219	
220	    // Opposite pairs: (TL,BR) and (TR,BL)
221	    int pairs[2][2] = {{0, 3}, {1, 2}};
222	    for (auto& pair : pairs) {
223	        double combined = corners[pair[0]].score + corners[pair[1]].score;
224	        if (combined > best_pair_score) {
225	            best_pair_score = combined;
226	            best_pair[0] = pair[0];
227	            best_pair[1] = pair[1];
228	        }
229	    }
230	
231	    // Also try single best corner (all humans in one corner)
232	    double best_single_score = -1;
233	    int best_single = 0;
234	    for (int i = 0; i < 4; i++) {
235	        if (corners[i].score > best_single_score) {
236	            best_single_score = corners[i].score;
237	            best_single = i;
238	        }
239	    }
240	
241	    // Compare with dual horizontal walls
242	    double best_dual_h = -1;
243	    int best_tr = 8, best_br = 23;
244	    for (int tr = 3; tr <= 15; tr++) {
245	        for (int br = tr + 4; br <= 28; br++) {
246	            double s = compute_dual_wall_score(tr, br);
247	            if (s > best_dual_h) {
248	                best_dual_h = s;
249	                best_tr = tr;
250	                best_br = br;
251	            }
252	        }
253	    }
254	
255	    // Choose strategy
256	    // L-shape advantages: faster build, better pet isolation when corners are clean
257	    // Give L-shape a 20% bonus for faster construction
258	    double l_pair_effective = best_pair_score * 1.2;
259	    double l_single_effective = best_single_score * 1.3; // single is even faster
260	
261	    if (l_pair_effective > best_dual_h && l_pair_effective > l_single_effective) {
262	        strategy_mode = 0;
263	        num_plans = 2;
264	        plans[0] = corners[best_pair[0]];
265	        plans[1] = corners[best_pair[1]];
266	    } else if (l_single_effective > best_dual_h) {
267	        strategy_mode = 0;
268	        num_plans = 1;
269	        plans[0] = corners[best_single];
270	    } else {
271	        strategy_mode = 1;
272	        dual_wall_top = best_tr;
273	        dual_wall_bot = best_br;
274	    }
275	}
276	
277	// Human assignment for L-shape strategy
278	int human_plan_assignment[10]; // which plan (0 or 1)
279	
280	// Wall cells to build for each plan
281	std::vector<Point> plan_walls[2];
282	
283	void assign_humans_lshape() {
284	    if (num_plans == 1) {
285	        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
286	        return;
287	    }
288	
289	    // Split humans between two plans based on proximity
290	    int count0 = M / 2;
291	
292	    std::vector<std::pair<double, int>> preference(M);
293	    for (int i = 0; i < M; i++) {
294	        // Distance to center of plan 0 region
295	        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
296	        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
297	        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
298	
299	        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
300	        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
301	        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
302	
303	        preference[i] = {d0 - d1, i};
304	    }
305	    std::sort(preference.begin(), preference.end());
306	
307	    int assigned0 = 0;
308	    for (auto& [pref, idx] : preference) {
309	        if (assigned0 < count0) {
310	            human_plan_assignment[idx] = 0;
311	            assigned0++;
312	        } else {
313	            human_plan_assignment[idx] = 1;
314	        }
315	    }
316	}
317	
318	// For dual horizontal wall fallback
319	int human_wall_assignment_h[10]; // 0=top, 1=bot
320	
321	void assign_humans_dual_h() {
322	    int top_count = M / 2;
323	    std::vector<std::pair<int, int>> preference(M);
324	    for (int i = 0; i < M; i++) {
325	        preference[i] = {std::abs(humans[i].r - dual_wall_top) - std::abs(humans[i].r - dual_wall_bot), i};
326	    }
327	    std::sort(preference.begin(), preference.end());
328	    int assigned_top = 0;
329	    for (auto& [pref, idx] : preference) {
330	        if (assigned_top < top_count) {
331	            human_wall_assignment_h[idx] = 0;
332	            assigned_top++;
333	        } else {
334	            human_wall_assignment_h[idx] = 1;
335	        }
336	    }
337	}
