339	int main() {
340	    std::ios_base::sync_with_stdio(false);
341	    std::cin.tie(NULL);
342	
343	    std::cin >> N;
344	    pets.resize(N);
345	    pet_types.resize(N);
346	    for (int i = 0; i < N; i++) {
347	        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
348	    }
349	
350	    std::cin >> M;
351	    humans.resize(M);
352	    for (int i = 0; i < M; i++) {
353	        std::cin >> humans[i].r >> humans[i].c;
354	    }
355	
356	    memset(grid, false, sizeof(grid));
357	    choose_strategy();
358	
359	    if (strategy_mode == 0) {
360	        // L-shape mode
361	        for (int p = 0; p < num_plans; p++) {
362	            plan_walls[p] = get_wall_cells(plans[p]);
363	        }
364	        assign_humans_lshape();
365	    } else {
366	        // Dual horizontal wall mode
367	        assign_humans_dual_h();
368	    }
369	
370	    for (int turn = 0; turn < NUM_TURNS; turn++) {
371	        std::string actions(M, '.');
372	        std::vector<Point> walls_being_built;
373	
374	        if (strategy_mode == 0) {
375	            // L-shape strategy
376	            for (int i = 0; i < M; i++) {
377	                int my_plan = human_plan_assignment[i];
378	                auto& my_walls = plan_walls[my_plan];
379	                auto& plan = plans[my_plan];
380	
381	                // Find nearest unbuilt wall cell
382	                int best_idx = -1;
383	                int best_dist = INF;
384	
385	                for (int w = 0; w < (int)my_walls.size(); w++) {
386	                    Point wc = my_walls[w];
387	                    if (grid[wc.r][wc.c]) continue;
388	
389	                    // Check not already claimed this turn
390	                    bool claimed = false;
391	                    for (auto& wb : walls_being_built) {
392	                        if (wb == wc) { claimed = true; break; }
393	                    }
394	                    if (claimed) continue;
395	
396	                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
397	                    if (dist < best_dist) {
398	                        best_dist = dist;
399	                        best_idx = w;
400	                    }
401	                }
402	
403	                if (best_idx == -1) {
404	                    // All walls built - move to center of safe zone
405	                    int tr = (plan.r_min + plan.r_max) / 2;
406	                    int tc = (plan.c_min + plan.c_max) / 2;
407	                    Point target = {tr, tc};
408	                    if (!passable(target.r, target.c)) {
409	                        // Find any passable cell in safe zone
410	                        bool found = false;
411	                        for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
412	                            for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
413	                                if (passable(r, c)) {
414	                                    target = {r, c};
415	                                    found = true;
416	                                }
417	                            }
418	                        }
419	                    }
420	                    if (humans[i] != target) {
421	                        actions[i] = move_toward(humans[i], target);
422	                    }
423	                } else {
424	                    Point wall_target = my_walls[best_idx];
425	
426	                    // Find a position adjacent to wall_target from the SAFE side
427	                    Point stand_pos = {-1, -1};
428	                    int best_stand_dist = INF;
429	
430	                    for (int d = 0; d < 4; d++) {
431	                        int sr = wall_target.r + DR[d];
432	                        int sc = wall_target.c + DC[d];
433	                        if (!passable(sr, sc)) continue;
434	
435	                        // Prefer standing inside the safe zone
436	                        bool in_safe = is_safe_side(plan, sr, sc);
437	
438	                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
439	                        // Give big bonus to safe-side positions
440	                        int effective_dist = in_safe ? dist : dist + 100;
441	
442	                        if (effective_dist < best_stand_dist) {
443	                            best_stand_dist = effective_dist;
444	                            stand_pos = {sr, sc};
445	                        }
446	                    }
447	
448	                    if (stand_pos.r == -1) {
449	                        // Can't find standing position, try any adjacent
450	                        for (int d = 0; d < 4; d++) {
451	                            int sr = wall_target.r + DR[d];
452	                            int sc = wall_target.c + DC[d];
453	                            if (passable(sr, sc)) {
454	                                stand_pos = {sr, sc};
455	                                break;
456	                            }
457	                        }
458	                    }
459	
460	                    if (stand_pos.r == -1) {
461	                        actions[i] = '.';
462	                    } else if (humans[i] == stand_pos) {
463	                        // Build the wall
464	                        if (can_build_wall(wall_target.r, wall_target.c)) {
465	                            for (int d = 0; d < 4; d++) {
466	                                if (humans[i].r + DR[d] == wall_target.r &&
467	                                    humans[i].c + DC[d] == wall_target.c) {
468	                                    actions[i] = BUILD_CH[d];
469	                                    walls_being_built.push_back(wall_target);
470	                                    break;
471	                                }
472	                            }
473	                        } else {
474	                            // Pet blocking - try building a different adjacent wall cell
475	                            bool built_alt = false;
476	                            for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
477	                                if (w2 == best_idx) continue;
478	                                Point wc2 = my_walls[w2];
479	                                if (grid[wc2.r][wc2.c]) continue;
480	                                if (!can_build_wall(wc2.r, wc2.c)) continue;
481	
482	                                bool adjacent = false;
483	                                int build_dir = -1;
484	                                for (int d = 0; d < 4; d++) {
485	                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
486	                                        adjacent = true;
487	                                        build_dir = d;
488	                                        break;
489	                                    }
490	                                }
491	                                if (adjacent) {
492	                                    actions[i] = BUILD_CH[build_dir];
493	                                    walls_being_built.push_back(wc2);
494	                                    built_alt = true;
495	                                    break;
496	                                }
497	                            }
498	                            if (!built_alt) actions[i] = '.';
499	                        }
500	                    } else {
501	                        // Move toward standing position
502	                        actions[i] = move_toward(humans[i], stand_pos);
503	                    }
504	                }
505	            }
506	        } else {
507	            // Dual horizontal wall strategy (fallback)
508	            bool col_claimed_top[GRID_SIZE + 2], col_claimed_bot[GRID_SIZE + 2];
509	            memset(col_claimed_top, false, sizeof(col_claimed_top));
510	            memset(col_claimed_bot, false, sizeof(col_claimed_bot));
511	
512	            for (int i = 0; i < M; i++) {
513	                int my_wall_row = (human_wall_assignment_h[i] == 0) ? dual_wall_top : dual_wall_bot;
514	                bool* my_claimed = (human_wall_assignment_h[i] == 0) ? col_claimed_top : col_claimed_bot;
515	
516	                // Check if wall is complete
517	                bool wall_done = true;
518	                for (int c = 1; c <= GRID_SIZE; c++) {
519	                    if (!grid[my_wall_row][c]) { wall_done = false; break; }
520	                }
521	
522	                if (wall_done) {
523	                    // Move to safe zone
524	                    int safe_r;
525	                    if (human_wall_assignment_h[i] == 0) {
526	                        safe_r = std::max(1, dual_wall_top / 2);
527	                    } else {
528	                        safe_r = std::min(GRID_SIZE, dual_wall_bot + (GRID_SIZE - dual_wall_bot) / 2);
529	                    }
530	                    Point target = {safe_r, GRID_SIZE / 2};
531	                    if (!passable(target.r, target.c)) {
532	                        int s, e;
533	                        if (human_wall_assignment_h[i] == 0) { s = 1; e = dual_wall_top - 1; }
534	                        else { s = dual_wall_bot + 1; e = GRID_SIZE; }
535	                        for (int r = s; r <= e; r++) {
536	                            for (int c = 1; c <= GRID_SIZE; c++) {
537	                                if (passable(r, c)) { target = {r, c}; goto found_target; }
538	                            }
