# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Phase-based strategy:
// Phase 0: Build initial L-shape (all humans)
// Phase 1: Extend horizontal wall to full width (converting L-zone to full strip)
// Phase 2: Done, humans idle in safe zone

int phase = 0;
int corner_id; // 0=TL, 1=TR, 2=BL, 3=BR
int wall_row, wall_col;
int safe_r_min, safe_r_max, safe_c_min, safe_c_max;

std::vector<Point> current_walls; // walls to build in current phase
std::vector<Point> extension_walls; // walls for phase 1

// Count pets in a rectangular region
int count_pets_in_region(int r_min, int r_max, int c_min, int c_max) {
    int count = 0;
    for (auto& p : pets) {
        if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
            count++;
        }
    }
    return count;
}

struct CornerOption {
    int corner;
    int wr, wc;
    int area;
    int cost;
    int pets_inside;
    int r_min, r_max, c_min, c_max;
    double score;
    // Extension info
    int ext_area; // area after full horizontal extension
    int ext_cost; // additional cells needed for extension
    int ext_r_min, ext_r_max, ext_c_min, ext_c_max;
};

void get_corner_bounds(int corner, int wr, int wc, int& r_min, int& r_max, int& c_min, int& c_max) {
    if (corner == 0) { r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1; }
    else if (corner == 1) { r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE; }
    else if (corner == 2) { r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1; }
    else { r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE; }
}

int get_lshape_cost(int corner, int wr, int wc) {
    if (corner == 0) return wc + (wr - 1);
    else if (corner == 1) return (GRID_SIZE - wc + 1) + (wr - 1);
    else if (corner == 2) return wc + (GRID_SIZE - wr);
    else return (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
}

std::vector<Point> get_lshape_walls(int corner, int wr, int wc) {
    std::vector<Point> cells;
    if (corner == 0) {
        for (int c = 1; c <= wc; c++) cells.push_back({wr, c});
        for (int r = 1; r < wr; r++) cells.push_back({r, wc});
    } else if (corner == 1) {
        for (int c = wc; c <= GRID_SIZE; c++) cells.push_back({wr, c});
        for (int r = 1; r < wr; r++) cells.push_back({r, wc});
    } else if (corner == 2) {
        for (int c = 1; c <= wc; c++) cells.push_back({wr, c});
        for (int r = wr + 1; r <= GRID_SIZE; r++) cells.push_back({r, wc});
    } else {
        for (int c = wc; c <= GRID_SIZE; c++) cells.push_back({wr, c});
        for (int r = wr + 1; r <= GRID_SIZE; r++) cells.push_back({r, wc});
    }
    return cells;
}

// Get extension walls: extend horizontal wall to full width (remove vertical wall need)
std::vector<Point> get_extension_walls(int corner, int wr, int wc) {
    std::vector<Point> cells;
    if (corner == 0) {
        // Extend horizontal wall at row wr from col wc+1 to col 30
        for (int c = wc + 1; c <= GRID_SIZE; c++) cells.push_back({wr, c});
    } else if (corner == 1) {
        // Extend horizontal wall at row wr from col 1 to col wc-1
        for (int c = 1; c < wc; c++) cells.push_back({wr, c});
    } else if (corner == 2) {
        // Extend horizontal wall at row wr from col wc+1 to col 30
        for (int c = wc + 1; c <= GRID_SIZE; c++) cells.push_back({wr, c});
    } else {
        // Extend horizontal wall at row wr from col 1 to col wc-1
        for (int c = 1; c < wc; c++) cells.push_back({wr, c});
    }
    return cells;
}

void get_extended_bounds(int corner, int wr, int& r_min, int& r_max, int& c_min, int& c_max) {
    // Full-width strip after extension
    if (corner == 0 || corner == 1) {
        r_min = 1; r_max = wr - 1; c_min = 1; c_max = GRID_SIZE;
    } else {
        r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = GRID_SIZE;
    }
}

CornerOption best_option;

void choose_strategy() {
    best_option.score = -1;

    for (int corner = 0; corner < 4; corner++) {
        // For each corner, try various L-shape sizes
        // We want an L-shape that's fast to build AND has a good extension potential
        for (int wr = 3; wr <= 12; wr++) {
            for (int wc = 3; wc <= 12; wc++) {
                int actual_wr = wr, actual_wc = wc;
                // Map to actual grid coordinates based on corner
                if (corner == 1) actual_wc = GRID_SIZE + 1 - wc; // mirror for TR
                else if (corner == 2) actual_wr = GRID_SIZE + 1 - wr; // mirror for BL
                else if (corner == 3) { actual_wr = GRID_SIZE + 1 - wr; actual_wc = GRID_SIZE + 1 - wc; } // mirror for BR

                int r_min, r_max, c_min, c_max;
                get_corner_bounds(corner, actual_wr, actual_wc, r_min, r_max, c_min, c_max);

                int area = (r_max - r_min + 1) * (c_max - c_min + 1);
                if (area < 20) continue;

                int cost = get_lshape_cost(corner, actual_wr, actual_wc);
                if (cost > 25) continue; // keep initial L-shape cheap

                int pets_inside = count_pets_in_region(r_min, r_max, c_min, c_max);

                // Also check extended region (full strip)
                int ext_r_min, ext_r_max, ext_c_min, ext_c_max;
                get_extended_bounds(corner, actual_wr, ext_r_min, ext_r_max, ext_c_min, ext_c_max);
                int ext_area = (ext_r_max - ext_r_min + 1) * (ext_c_max - ext_c_min + 1);
                int ext_pets = count_pets_in_region(ext_r_min, ext_r_max, ext_c_min, ext_c_max);

                auto ext_walls = get_extension_walls(corner, actual_wr, actual_wc);
                int ext_cost = (int)ext_walls.size();

                // Score: consider both the L-shape alone and the L-shape + extension
                // If extension is pet-free, we'll definitely extend (much more area)
                // The combined score weighs area potential

                double l_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
                double ext_score = (double)ext_area / 900.0 * std::pow(2.0, -(double)ext_pets);

                // Prefer options where:
                // 1. Initial L-shape has 0 pets (essential for phase 0 safety)
                // 2. Extended area also has 0 pets (good extension potential)
                // 3. Low initial cost (fast phase 0)
                // 4. High extended area

                if (pets_inside > 0) continue; // require pet-free initial L-shape

                // Build priority score
                double score;
                if (ext_pets == 0) {
                    // Great extension potential - prioritize ext_area with cost penalty
                    score = ext_score * 2.0 / (1.0 + cost * 0.02 + ext_cost * 0.01);
                } else {
                    // Extension has pets - just use L-shape value
                    score = l_score * 1.0 / (1.0 + cost * 0.02);
                }

                if (score > best_option.score) {
                    best_option.corner = corner;
                    best_option.wr = actual_wr;
                    best_option.wc = actual_wc;
                    best_option.area = area;
                    best_option.cost = cost;
                    best_option.pets_inside = pets_inside;
                    best_option.r_min = r_min;
                    best_option.r_max = r_max;
                    best_option.c_min = c_min;
                    best_option.c_max = c_max;
                    best_option.score = score;
                    best_option.ext_area = ext_area;
                    best_option.ext_cost = ext_cost;
                    best_option.ext_r_min = ext_r_min;
                    best_option.ext_r_max = ext_r_max;
                    best_option.ext_c_min = ext_c_min;
                    best_option.ext_c_max = ext_c_max;
                }
            }
        }
    }

    // Fallback: if no good option found, use a default
    if (best_option.score < 0) {
        best_option.corner = 0;
        best_option.wr = 6;
        best_option.wc = 6;
        best_option.area = 25;
        best_option.cost = 11;
        best_option.pets_inside = 0;
        best_option.r_min = 1; best_option.r_max = 5;
        best_option.c_min = 1; best_option.c_max = 5;
        best_option.score = 0.01;
        best_option.ext_area = 150;
        best_option.ext_cost = 24;
        best_option.ext_r_min = 1; best_option.ext_r_max = 5;
        best_option.ext_c_min = 1; best_option.ext_c_max = GRID_SIZE;
    }
}

bool all_walls_built(const std::vector<Point>& walls) {
    for (auto& w : walls) {
        if (!grid[w.r][w.c]) return false;
    }
    return true;
}

// Try to transition from phase 0 to phase 1
void try_phase_transition() {
    if (phase == 0 && all_walls_built(current_walls)) {
        // L-shape is complete! Check if extension is viable
        int ext_r_min, ext_r_max, ext_c_min, ext_c_max;
        get_extended_bounds(best_option.corner, best_option.wr, ext_r_min, ext_r_max, ext_c_min, ext_c_max);
        int ext_pets = count_pets_in_region(ext_r_min, ext_r_max, ext_c_min, ext_c_max);

        if (ext_pets == 0) {
            // Extension is pet-free! Build it
            phase = 1;
            current_walls = extension_walls;
            safe_r_min = ext_r_min;
            safe_r_max = ext_r_max;
            safe_c_min = ext_c_min;
            safe_c_max = ext_c_max;
        } else {
            // Extension has pets - just stay in L-shape zone
            phase = 2;
            safe_r_min = best_option.r_min;
            safe_r_max = best_option.r_max;
            safe_c_min = best_option.c_min;
            safe_c_max = best_option.c_max;
        }
    } else if (phase == 1 && all_walls_built(current_walls)) {
        // Extension complete!
        phase = 2;
        // safe bounds already set to extended bounds
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

