    current_walls = get_lshape_walls(corner_id, wall_row, wall_col);
    extension_walls = get_extension_walls(corner_id, wall_row, wall_col);

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        try_phase_transition();

        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        if (phase == 2) {
            // All done - move humans to center of safe zone
            for (int i = 0; i < M; i++) {
                int tr = (safe_r_min + safe_r_max) / 2;
                int tc = (safe_c_min + safe_c_max) / 2;
                Point target = {tr, tc};
                if (!passable(target.r, target.c)) {
                    bool found = false;
                    for (int r = safe_r_min; r <= safe_r_max && !found; r++) {
                        for (int c = safe_c_min; c <= safe_c_max && !found; c++) {
                            if (passable(r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                }
                if (humans[i] != target) {
                    actions[i] = move_toward(humans[i], target);
                }
            }
        } else {
            // Building phase (0 or 1): all humans build current_walls
            for (int i = 0; i < M; i++) {
                // Find nearest unbuilt wall cell not claimed by another human this turn
                int best_idx = -1;
                int best_dist = INF;

                for (int w = 0; w < (int)current_walls.size(); w++) {
                    Point wc = current_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) {
                        best_dist = dist;
                        best_idx = w;
                    }
                }

                if (best_idx == -1) {
                    // No unbuilt walls remain - move to safe zone
                    int tr = (safe_r_min + safe_r_max) / 2;
                    int tc = (safe_c_min + safe_c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        for (int r = safe_r_min; r <= safe_r_max; r++) {
                            for (int c = safe_c_min; c <= safe_c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_idle; }
                            }
                        }
                        found_idle:;
                    }
                    if (humans[i] != target) {
                        actions[i] = move_toward(humans[i], target);
                    }
                    continue;
                }

                Point wall_target = current_walls[best_idx];
                walls_being_built.push_back(wall_target);

