        best_option.ext_r_min = 1; best_option.ext_r_max = 5;
        best_option.ext_c_min = 1; best_option.ext_c_max = GRID_SIZE;
    }
}

bool all_walls_built(const std::vector<Point>& walls) {
    for (auto& w : walls) {
        if (!grid[w.r][w.c]) return false;
    }
    return true;
}

// Try to transition from phase 0 to phase 1
void try_phase_transition() {
    if (phase == 0 && all_walls_built(current_walls)) {
        // L-shape is complete! Check if extension is viable
        int ext_r_min, ext_r_max, ext_c_min, ext_c_max;
        get_extended_bounds(best_option.corner, best_option.wr, ext_r_min, ext_r_max, ext_c_min, ext_c_max);
        int ext_pets = count_pets_in_region(ext_r_min, ext_r_max, ext_c_min, ext_c_max);

        if (ext_pets == 0) {
            // Extension is pet-free! Build it
            phase = 1;
            current_walls = extension_walls;
            safe_r_min = ext_r_min;
            safe_r_max = ext_r_max;
            safe_c_min = ext_c_min;
            safe_c_max = ext_c_max;
        } else {
            // Extension has pets - just stay in L-shape zone
            phase = 2;
            safe_r_min = best_option.r_min;
            safe_r_max = best_option.r_max;
            safe_c_min = best_option.c_min;
            safe_c_max = best_option.c_max;
        }
    } else if (phase == 1 && all_walls_built(current_walls)) {
        // Extension complete!
        phase = 2;
        // safe bounds already set to extended bounds
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
