                int best_idx = -1;
                int best_dist = INF;

                for (int w = 0; w < (int)current_walls.size(); w++) {
                    Point wc = current_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) {
                        best_dist = dist;
                        best_idx = w;
                    }
                }

                if (best_idx == -1) {
