                    int tr = (safe_r_min + safe_r_max) / 2;
                    int tc = (safe_c_min + safe_c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        for (int r = safe_r_min; r <= safe_r_max; r++) {
                            for (int c = safe_c_min; c <= safe_c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_idle; }
                            }
                        }
                        found_idle:;
                    }
