                            int sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) {
                                stand_pos = {sr, sc};
                                break;
                            }
                        }
                    }

                    if (stand_pos.r == -1) {
                        actions[i] = '.';
                    } else if (humans[i] == stand_pos) {
                        if (can_build_wall(wall_target.r, wall_target.c)) {
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wall_target.r &&
                                    humans[i].c + DC[d] == wall_target.c) {
                                    actions[i] = BUILD_CH[d];
                                    break;
                                }
                            }
                        } else {
                            // Pet blocking - try building a different adjacent wall cell
                            bool built_alt = false;
                            for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
