                                bool adjacent = false;
                                int build_dir = -1;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        adjacent = true;
