                                    walls_being_built.push_back(wc2);
                                    built_alt = true;
                                    break;
                                }
                            }
                            if (!built_alt) actions[i] = '.';
                        }
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }
        } else {
            // Dual horizontal wall strategy (fallback)
            bool col_claimed_top[GRID_SIZE + 2], col_claimed_bot[GRID_SIZE + 2];
            memset(col_claimed_top, false, sizeof(col_claimed_top));
            memset(col_claimed_bot, false, sizeof(col_claimed_bot));

