            else if (corner_id == 2) { r_min = wr+1; r_max = GRID_SIZE; c_min = 1; c_max = wc-1; cost = wc + (GRID_SIZE-wr); }
            else { r_min = wr+1; r_max = GRID_SIZE; c_min = wc+1; c_max = GRID_SIZE; cost = (GRID_SIZE-wc+1) + (GRID_SIZE-wr); }

            int area = (r_max - r_min + 1) * (c_max - c_min + 1);
            if (area < 50 || cost > 40) continue;

            int pets_inside = count_pets_in_region(r_min, r_max, c_min, c_max);
            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
            double time_factor = 1.0 / (1.0 + cost * 0.01);
            double pet_bonus = (pets_inside == 0) ? 2.0 : 1.0;
            double score = base_score * time_factor * pet_bonus;

            if (score > best.score) {
                best = {corner_id, wr, wc, area, cost, pets_inside, score, r_min, r_max, c_min, c_max};
            }
        }
    }
}

// Global state
int num_zones; // 1 or 2
Plan zones[2]; // the zones we're building

int human_zone_assignment[10];

void assign_humans() {
    if (num_zones == 1) {
        for (int i = 0; i < M; i++) human_zone_assignment[i] = 0;
        return;
    }
    int count0 = M / 2;
    std::vector<std::pair<double, int>> pref(M);
    for (int i = 0; i < M; i++) {
        double cr0 = (zones[0].r_min + zones[0].r_max) / 2.0;
        double cc0 = (zones[0].c_min + zones[0].c_max) / 2.0;
        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
        double cr1 = (zones[1].r_min + zones[1].r_max) / 2.0;
        double cc1 = (zones[1].c_min + zones[1].c_max) / 2.0;
        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
        pref[i] = {d0 - d1, i};
    }
    std::sort(pref.begin(), pref.end());
    int assigned0 = 0;
    for (auto& [p, idx] : pref) {
        if (assigned0 < count0) { human_zone_assignment[idx] = 0; assigned0++; }
        else { human_zone_assignment[idx] = 1; }
    }
}

void choose_strategy() {
    // Find best U-shapes along each edge
    Plan u_plans[4];
    u_plans[0] = find_best_u_top();
    u_plans[1] = find_best_u_bottom();
    u_plans[2] = find_best_u_left();
    u_plans[3] = find_best_u_right();

    // Find best L-shapes (corners)
    CornerPlan corners[4];
    for (int i = 0; i < 4; i++) find_best_corner(i, corners[i]);

    // Convert corners to Plan format
    Plan l_plans[4];
    for (int i = 0; i < 4; i++) {
        l_plans[i].r_min = corners[i].r_min; l_plans[i].r_max = corners[i].r_max;
        l_plans[i].c_min = corners[i].c_min; l_plans[i].c_max = corners[i].c_max;
        l_plans[i].area = corners[i].area; l_plans[i].cost = corners[i].cost;
        l_plans[i].pets_inside = corners[i].pets_inside; l_plans[i].score = corners[i].score;
        l_plans[i].walls = get_corner_wall_cells(corners[i]);
    }

    // Collect all candidates: individual zones
    std::vector<Plan> all_plans;
    for (int i = 0; i < 4; i++) { if (u_plans[i].score > 0) all_plans.push_back(u_plans[i]); }
    for (int i = 0; i < 4; i++) { if (l_plans[i].score > 0) all_plans.push_back(l_plans[i]); }

    // Sort by score
    std::sort(all_plans.begin(), all_plans.end(), [](const Plan& a, const Plan& b) {
        return a.score > b.score;
    });

    if (all_plans.empty()) {
        // Fallback: simple top L-shape
        num_zones = 1;
        zones[0].r_min = 1; zones[0].r_max = 5; zones[0].c_min = 1; zones[0].c_max = 5;
        zones[0].area = 25; zones[0].cost = 11; zones[0].pets_inside = 0; zones[0].score = 0.01;
        for (int c = 1; c <= 6; c++) zones[0].walls.push_back({6, c});
        for (int r = 1; r <= 5; r++) zones[0].walls.push_back({r, 6});
        return;
    }

    // Try pairs of non-overlapping zones
    double best_pair_score = -1;
    int best_i = -1, best_j = -1;

    for (int i = 0; i < (int)all_plans.size() && i < 8; i++) {
        for (int j = i + 1; j < (int)all_plans.size() && j < 8; j++) {
            // Check non-overlapping (wall cells don't conflict, regions don't overlap)
            bool overlap = false;
            if (all_plans[i].r_min <= all_plans[j].r_max && all_plans[j].r_min <= all_plans[i].r_max &&
                all_plans[i].c_min <= all_plans[j].c_max && all_plans[j].c_min <= all_plans[i].c_max) {
                overlap = true;
            }
            // Also check wall overlap with other's region
            for (auto& w : all_plans[i].walls) {
                if (w.r >= all_plans[j].r_min && w.r <= all_plans[j].r_max &&
                    w.c >= all_plans[j].c_min && w.c <= all_plans[j].c_max) {
                    overlap = true; break;
                }
            }
            if (!overlap) {
                for (auto& w : all_plans[j].walls) {
                    if (w.r >= all_plans[i].r_min && w.r <= all_plans[i].r_max &&
                        w.c >= all_plans[i].c_min && w.c <= all_plans[i].c_max) {
                        overlap = true; break;
                    }
                }
            }
            if (overlap) continue;

            double combined = all_plans[i].score + all_plans[j].score;
            // Penalize pair if total cost is too high for M humans
            int total_cost = all_plans[i].cost + all_plans[j].cost;
            double cost_penalty = 1.0 / (1.0 + total_cost * 0.005);
            combined *= cost_penalty;

            if (combined > best_pair_score) {
                best_pair_score = combined;
                best_i = i; best_j = j;
            }
        }
    }

    // Compare best single vs best pair
    double best_single = all_plans[0].score * 1.3; // single gets speed bonus
    if (best_pair_score > best_single && best_i >= 0) {
        num_zones = 2;
        zones[0] = all_plans[best_i];
        zones[1] = all_plans[best_j];
    } else {
        num_zones = 1;
        zones[0] = all_plans[0];
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_strategy();
    assign_humans();

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        for (int i = 0; i < M; i++) {
            int my_zone = human_zone_assignment[i];
            auto& my_walls = zones[my_zone].walls;
            auto& zone = zones[my_zone];

            // Find nearest unbuilt wall cell
            int best_idx = -1;
            int best_dist = INF;

            for (int w = 0; w < (int)my_walls.size(); w++) {
                Point wc = my_walls[w];
                if (grid[wc.r][wc.c]) continue;

                bool claimed = false;
                for (auto& wb : walls_being_built) {
                    if (wb == wc) { claimed = true; break; }
                }
                if (claimed) continue;

                int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                if (dist < best_dist) {
                    best_dist = dist;
                    best_idx = w;
                }
            }

            if (best_idx == -1) {
                // All walls built - move into safe zone
                int tr = (zone.r_min + zone.r_max) / 2;
                int tc = (zone.c_min + zone.c_max) / 2;
                Point target = {tr, tc};
                if (!passable(target.r, target.c)) {
                    bool found = false;
                    for (int r = zone.r_min; r <= zone.r_max && !found; r++) {
                        for (int c = zone.c_min; c <= zone.c_max && !found; c++) {
                            if (passable(r, c)) { target = {r, c}; found = true; }
                        }
                    }
                }
                if (humans[i] != target) {
                    actions[i] = move_toward(humans[i], target);
                }
            } else {
                Point wall_target = my_walls[best_idx];
                walls_being_built.push_back(wall_target);

                // Find standing position adjacent to wall_target, prefer safe side
                Point stand_pos = {-1, -1};
                int best_stand_dist = INF;

                for (int d = 0; d < 4; d++) {
                    int sr = wall_target.r + DR[d];
                    int sc = wall_target.c + DC[d];
                    if (!passable(sr, sc)) continue;

                    bool in_safe = (sr >= zone.r_min && sr <= zone.r_max &&
                                    sc >= zone.c_min && sc <= zone.c_max);
                    int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                    int effective_dist = in_safe ? dist : dist + 100;

                    if (effective_dist < best_stand_dist) {
                        best_stand_dist = effective_dist;
                        stand_pos = {sr, sc};
                    }
                }

                if (stand_pos.r == -1) {
                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d];
                        int sc = wall_target.c + DC[d];
                        if (passable(sr, sc)) { stand_pos = {sr, sc}; break; }
                    }
                }

                if (stand_pos.r == -1) {
                    actions[i] = '.';
                } else if (humans[i] == stand_pos) {
                    if (can_build_wall(wall_target.r, wall_target.c)) {
                        for (int d = 0; d < 4; d++) {
                            if (humans[i].r + DR[d] == wall_target.r &&
                                humans[i].c + DC[d] == wall_target.c) {
                                actions[i] = BUILD_CH[d];
                                break;
                            }
                        }
                    } else {
                        bool built_alt = false;
                        for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
                            if (w2 == best_idx) continue;
                            Point wc2 = my_walls[w2];
                            if (grid[wc2.r][wc2.c]) continue;
                            if (!can_build_wall(wc2.r, wc2.c)) continue;
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back(wc2);
                                    built_alt = true;
                                    break;
                                }
                            }
                            if (built_alt) break;
                        }
                        if (!built_alt) actions[i] = '.';
                    }
                } else {
                    actions[i] = move_toward(humans[i], stand_pos);
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
